#!/usr/bin/env python3# -*- coding: utf-8 -*-"""Created on Thu Dec 17 10:57:37 2025@author: sshenoy""""""This is the main MakeFlat class to generate MIRI LRS flats."""import osimport numpy as npfrom astropy.modeling.functional_models import Linear1D, Gaussian1D, Moffat1Dfrom astropy.modeling import fittingfrom jwst import datamodels as dmclass MakeFlat(object):    """Class to generate MIRI LRS flat"""        def __init__(self):        self.inpath = None        self.outpath = os.getcwd()        self.manifest = None        self.filelist = None        self.model_type = None        self.model_name = None        self.save = False                def read_manifest(self, manifest, inpath='./'):        """ Read the input manifest and generate a list of files        to process."""                # Check the input path        if os.path.isdir(inpath):            if inpath[-1] != '/':                inpath = inpath + '/'            self.inpath = inpath        else:            return("inpath, {}, does not exisit ".format(inpath))                if os.path.isfile(self.inpath+manifest):            self.manifest = self.inpath+manifest        else:            return("Input manifest, {}, does not exist".format(manifest))                flist = []                with open(self.manifest, 'r') as f:            for line in f.readlines():                if line[0] != '#':                    flist.append(os.path.abspath(line.split()[0]))                self.filelist = flist                return self.filelist            def fit_lrs_row(self, row_data, uncertainty=None,                     model_type=None, model=None,                     iparam=None):        # Remove Nan-ed data.        if uncertainty is None:            uncertainty = np.ones_like(row_data)            # Get get x (index) values.        tmp_x = np.arange(len(row_data))                if len(row_data) == len(uncertainty):            nan_mask = (~np.isnan(row_data)) & (~np.isnan(uncertainty))        else:            print("Input data and uncertainty have different size.")            print("Fitting without weights/")            nan_mask = ~np.isnan(row_data)            x = tmp_x[nan_mask]        masked_profile = row_data[nan_mask]        masked_profunc = np.sqrt(uncertainty[nan_mask]**2)            # Looks like there are some zeros in Uncertainty array, need to         # remove them.        masked_profunc[masked_profunc==0] = np.median(masked_profunc)                # Get peak index and value of the profile.        # These will be the initial guesses for the fit parameters.        try:            peak_idx = np.argmax(masked_profile)            peak_val = masked_profile[peak_idx]        except ValueError:            peak_idx = np.nan            peak_val = np.nan            # Set the initial guesses for the fit parameters.         start_values = {'intercept': 0.1,                         'slope': 0.01,                         'amplitude': peak_val,                         'mean': peak_idx,                         'stddev': np.sqrt(2 * np.log(2)),                          'x_0': peak_idx,                         'gamma': 1,                         'alpha': 1}            # Check user set guesses for fit parameters.        # if not set then use default values from above.        if iparam is None:            iparam = start_values        else:            all_keys = iparam.keys()            if not 'intercept' in all_keys:                iparam['intercept'] = start_values['intercept']            if not 'slope' in all_keys:                iparam['slope'] = start_values['slope']            if not 'amplitude' in all_keys:                iparam['amplitude'] = start_values['amplitude']            if not 'mean' in all_keys:                iparam['mean'] = start_values['mean']            if not 'stddev' in all_keys:                iparam['stddev'] = start_values['stddev']            if not 'amplitude' in all_keys:                iparam['amplitude'] = start_values['amplitude']            if not 'x_0' in all_keys:                iparam['x_0'] = start_values['x_0']            if not 'gamma' in all_keys:                iparam['gamma'] = start_values['gamma']            if not 'alpha' in all_keys:                iparam['alpha'] = start_values['alpha']            # Check the model keyword argument.        # If not set use default.        if model is None:            self.model_name = 'moffat'        else:            self.model_name = model.lower()            # Initialize the model.        if self.model_name.lower() == 'gaussian':            model_init = Gaussian1D(amplitude=iparam['amplitude'],                                     mean=iparam['mean'],                                     stddev=iparam['stddev'],                                    name=self.model_name)        elif self.model_name.lower() == 'moffat':            model_init = Moffat1D(amplitude=iparam['amplitude'],                                   x_0=iparam['x_0'],                                  gamma=iparam['gamma'],                                   alpha=iparam['alpha'],                                   name=self.model_name)        model_init.amplitude.min = 0.0            # Check the model_type keyword argument.        # If not set use default.        if model_type is None:            self.model_type = 'compound'        else:            self.model_type = model_type.lower()            # Initialze the final model.        if self.model_type.lower() == 'single':            compound_init = model_init        elif self.model_type.lower() == 'compound':            linear_init = Linear1D(intercept=iparam['intercept'],                                   slope=iparam['slope'],                                   name='linear')            compound_init = linear_init + model_init            compound_init.name = 'compound'            # Here I am using Levenberg-Marquardt algorithm and least squares         # statistic Future Update: User settable keyword argument for         # fitter.        fitter = fitting.LevMarLSQFitter(calc_uncertainties=True)            # Fit the model to masked row data.        try:            fitted_model = fitter(compound_init, x, masked_profile,                                   weights=(1/masked_profunc))        except Exception as e:            print(f"Caught and exception in fitting.\n {e}")            tmp_model = compound_init.copy()            tmp_model.parameters = np.nan            fitted_model = tmp_model                    return len(x), fitted_model            def prep_data_to_fit(self, file):        """        This function should take a fit file.        1. Figure out of it is LRS data (FILTER = P750L)        2. Figure out if it is slit/slitless             (KW = EXP_TYPE, SUBARRAY, APERNAME             slit = MIR_LRS-FIXEDSLIT, FULL, MIRIM_SLIT             slitless = MIR_LRS-SLITLES, SLITLESSPRISM, MIRIM_SLITLESSPRISM)        3. Mask the non-LRS region of the image if it is slit             1:430, 240:352 # There is more pixels on the left as the PSF             extendes there.         4. collapse all the rows (median)        5. fit a linear + gaussian (and or moffat) and get coeffcients        6. output cropped data, & fit coeffcients to use as initial guess             for fitting.        """            # Check if the file exist, else exit/return.        if not os.path.isfile(file):            print(f"Input file {file} not found.")            print("Please check the path to the file.")            return        else:            input_dm = dm.ImageModel(file)                # Check if the observation is LRS        i_filter = input_dm.meta.instrument.filter        if i_filter != 'P750L':            print("This is not a LRS data.")            print(f"Filter used is {i_filter}")            return            # Check if the data is SLIT or SLITLESS:        e_type, a_name, subarray = (input_dm.meta.exposure.type,                                    input_dm.meta.aperture.instance['name'],                                    input_dm.meta.subarray.name)                                            if (e_type, a_name, subarray) == ('MIR_LRS-SLITLESS',                                           'MIRIM_SLITLESSPRISM',                                           'SLITLESSPRISM'):            observation_type = 'slitess'        elif (e_type, a_name, subarray) == ('MIR_LRS-FIXEDSLIT',                                             'MIRIM_SLIT',                                             'FULL'):            observation_type = 'slit'        else:            print("Could not determine the observation type (slit/less).")            return                # Get the sci, err, and dq array        sci_array = input_dm.data        err_array = input_dm.err        dqf_array = input_dm.dq            if observation_type == 'slit':            cropped_sci = sci_array[2:430, 300:350]            cropped_err = err_array[2:430, 300:350]            cropped_dqf = dqf_array[2:430, 300:350]            cropped_pos = input_dm.var_poisson[2:430, 300:350]            cropped_red = input_dm.var_rnoise[2:430, 300:350]        else:            cropped_sci = sci_array            cropped_err = err_array            cropped_dqf = dqf_array            cropped_pos = input_dm.var_poisson            cropped_red = input_dm.var_rnoise            # Collapse all the rows        collapsed_sci = np.nanmedian(cropped_sci, axis=0)        collapsed_err = np.nanmedian(cropped_err, axis=0)        uncertainty_arr = collapsed_err + \                            np.sqrt(np.nanmedian(cropped_pos, axis=0)) + \                            np.sqrt(np.nanmedian(cropped_red, axis=0))                fit_length, \        fit_collapsed_data = self.fit_lrs_row(collapsed_sci,                                               uncertainty=uncertainty_arr,                                               model_type='compound')            output_dm = input_dm.copy()        output_dm.meta.filename = input_dm.meta.filename.replace('rate',                                                                  'crop')        output_dm.data = cropped_sci        output_dm.err = cropped_err        output_dm.dq = cropped_dqf        output_dm.var_poisson = cropped_pos        output_dm.var_rnoise = cropped_red        output_dm.rowavg = collapsed_sci        output_dm.rowunc = collapsed_err        output_dm.avglen = fit_length        output_dm.avgmod = fit_collapsed_data                return output_dm            def check_output_directory(self, dir_name, outpath=None):        if outpath is None:            cwd = os.getcwd()            if os.path.basename(cwd)=='script':                out_dir = os.path.join(os.getcwd(), './../proc', dir_name)            else:                out_dir = os.path.join(os.getcwd(), 'proc', dir_name)        else:            out_dir = os.path.join(os.path.abspath(outpath), dir_name)                    if not os.path.isdir(out_dir):            os.makedirs(out_dir)                    self.outpath = out_dir            return self.outpath            def fit_lrs_array(self, filename, model_type='compound', model='Moffat',                       outpath=None, save=False):        ### Check the input file and read it into variables.        if not os.path.isfile(filename):            print(f"File, {filename}, not found.")                ### Check model type, use default if not defined or has incorrect         ### value.        if model_type is None:            self.model_type = 'compound'        else:             if model_type.lower() not in ['single', 'compound']:                print("Model Type can only be 'single' or 'compound'.")                print("Using default model type: Compound.")                self.model_type = 'compound'            ### Check model, use default if not defined or has incorrect value.        if model is None:            self.model_name = 'moffat'        else:            if model.lower() not in ('gaussian', 'moffat'):                print("Currently only Gaussian and Moffat is implemented.")                print("Using default: Moffat model.")                self.model_name = 'moffat'                          ### Get the guess for fit parameters        cropped = self.prep_data_to_fit(filename)            guess = {}        for key, value in zip(cropped.avgmod.param_names,                               cropped.avgmod.parameters):            guess[key[:-2]] = value            fitlength = []        fitmodel = []            uncertainty_arr = cropped.err + \                            np.sqrt(cropped.var_poisson) + \                            np.sqrt(cropped.var_rnoise)                for row in np.arange(cropped.data.shape[0]):            # clear_output(wait=True)            if not np.isnan(cropped.data[row, :]).all():                row_length, \                row_model = self.fit_lrs_row(cropped.data[row, :],                                              uncertainty=uncertainty_arr[row, :],                                             model_type=self.model_type,                                             iparam=guess)                fitlength.append(row_length)                fitmodel.append(row_model)            else:                nan_model = cropped.avgmod.copy()                nan_model.parameters = np.nan                fitlength.append(len(cropped.data[row, :]))                fitmodel.append(nan_model)            fit_model = cropped.copy()        fit_model.meta.filename = cropped.meta.filename.replace('crop',                                                                 'fmod')        fit_model.fitlen = fitlength        fit_model.fitmod = fitmodel                if save:            mode = 'slit' if \                fit_model.meta.exposure.type=='MIR_LRS-FIXEDSLIT' else \                    'slitless'            out_dir = self.check_output_directory(mode, outpath=outpath)            fit_model.save(fit_model.meta.filename, dir_path=out_dir)                    return fit_model            def subtract_model_profile(self, filename, model_param=None,                                subtract='linear', outpath=None,                                save=False):        ### Get the guess for fit parameters        cropped = self.prep_data_to_fit(filename)                subtracted_array = np.zeros_like(cropped.data)        ### Need to find a robust method to get uncertainty in background.        ### Currently, the fit uncertainty are blowing up at lots of rows. :(         subtracted_uncer = np.full(cropped.err.shape, np.nan)        subtracted_dgflg = cropped.dq.copy()            if model_param is None:            if cropped.hasattr('avgmod'):                models = [cropped.avgmod] * cropped.data.shape[0]            else:                print("Fittted model not found in cropped collapsed data.")                return None        else:            if model_param.hasattr('fitmod'):                models = model_param.fitmod            else:                print("Fittted models not found model_param DataModel.")                return None                              if not subtract.lower() in ['linear', 'moffat', 'gaussian']:            print(f"{subtract} is not a valid model name.")            return None                          for row in np.arange(cropped.data.shape[0]):            if subtract is None:                x = np.full(len(cropped.data[row, :]), np.nan)            else:                x = np.arange(len(cropped.data[row, :]))                            sig_data = cropped.data[row, :]            sig_uncn = cropped.err[row, :]                try:                row_model = models[row][subtract]            except IndexError:                print(f"{subtract.capitalize()} model not found in the provided DataModel.")                return None                subtracted_array[row, :] = sig_data - row_model(x)            subtracted_uncer[row, :] = sig_uncn                     subtracted_ouput = cropped.copy()        ftype = 'psfs' if subtract.lower()=='linear' else 'bkgs'        subtracted_ouput.meta.filename = cropped.meta.filename.replace('crop', ftype)        subtracted_ouput.data = subtracted_array        subtracted_ouput.err = subtracted_uncer        subtracted_ouput.dq = subtracted_dgflg                if save:            mode = 'slit' if subtracted_ouput.meta.exposure.type=='MIR_LRS-FIXEDSLIT' else 'slitless'            out_dir = self.check_output_directory(mode, outpath=outpath)            subtracted_ouput.save(subtracted_ouput.meta.filename, dir_path=out_dir)            return subtracted_ouput                